css_snippet:
a {
  text-decoration: underline; /* Ensure underline is present */
  text-underline-offset: 0.2em; /* Lift underline slightly above descenders */
  text-decoration-thickness: 1px; /* Set a specific thickness for the underline */
  text-decoration-color: var(--link-color, #007bff); /* Match theme */
}

/* For a more modern approach, combining with 'text-decoration-line' */
.decorated-text {
  text-decoration-line: underline;
  text-underline-offset: 0.15em;
  text-decoration-thickness: from-font; /* Let the font suggest thickness, or specify a value */
  text-decoration-color: currentColor; /* Inherit text color */
}
